const fs = require('fs');
const html = fs.readFileSync('index.html','utf8');
// extract script content
const m = html.match(/<script>([\s\S]*?)<\/script>/);
if(!m){ console.log('no script'); process.exit(1); }
try {
  new Function(m[1]);
  console.log('JS syntax OK ('+m[1].length+' chars)');
} catch(e){ console.log('JS ERROR:', e.message); process.exit(1); }
// quick sanity: required ids
const ids = ['pet','moodBox','fedBox','energyBox','levelPill','statApproved','statDenied','statNapped','statTokens','statToday','btnFeed','btnPlay','btnNap','chatLog','chatInput','chatSend','settings','apiKey','model','resetAll','settingsBtn','pageNum'];
